text:
{
  "formal_minutes": {
    "decisions": [
      {
        "type": "확정",
        "item": "공개 릴리스 목표는 스모크 테스트 통과 시 금요일 15:00 KST로 확정."
      },
      {
        "type": "확정",
        "item": "packageName 불일치가 발생하면 먼저 패키지 설정(컨트랙트/구성)을 확인하고, 스크립트( smoke-theme-pack.mjs )는 계약 자체가 잘못된 경우에만 검토한다."
      },
      {
        "type": "확정",
        "item": "Minjun: 금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과 공유."
      },
      {
        "type": "확정",
        "item": "Doyun: 금요일 12:00 KST까지 실패 트리아지 노트를 action_items.md에 작성."
      }
    ],
    "rejected_proposals": [
      {
        "type": "거부",
        "item": "Hara의 ‘smoke-theme-pack.mjs에서 packageName 불일치 무시’ 제안은 회의에서 반려됨."
      }
    ],
    "internal_stretch_goals": [
      {
        "type": "내부 스트레치",
        "item": "수요일 릴리스 목표는 내부용 스트레치 목표로만 공유됨(공개 목표 아님)."
      }
    ],
    "non_decisions": [
      {
        "type": "비결정",
        "item": "README 설치 단계 검토는 필요하다는 의견만 있었고, 담당자 또는 확정 기한은 미할당."
      },
      {
        "type": "비결정",
        "item": "Hara의 tarball 경로 점검은 계획되었으나 정확한 완료 시한은 미정."
      }
    ],
    "risks": [
      {
        "type": "위험",
        "item": "tarball 경로가 잘못되면 릴리스가 지연될 수 있음."
      },
      {
        "type": "위험",
        "item": "README 설치 단계가 오래되면 릴리스 노트가 사용자에게 오해를 줄 수 있음."
      }
    ],
    "open_questions": [
      {
        "type": "미결 질문",
        "item": "최종 릴리스 승인 권한자는 누구인지 미결정."
      },
      {
        "type": "미결 질문",
        "item": "릴리스 노트에 내부 수요일 스트레치 목표를 언급할지 미결정."
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트 재실행 및 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "확정됨",
      "source_certainty": "높음"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 실패 트리아지 노트 작성",
      "due": "금요일 12:00 KST",
      "status": "확정됨",
      "source_certainty": "높음"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 후 생성된 tarball 경로 확인",
      "due": "시한 미정(결과 공유 이후)",
      "status": "진행 예정",
      "source_certainty": "중간"
    },
    {
      "owner": "미지정",
      "task": "README 설치 단계 최신성 검토",
      "due": "목요일 가능 시(정확 시한 미정)",
      "status": "할당 필요",
      "source_certainty": "낮음"
    }
  ],
  "followup_note": {
    "check_next": [
      "금요일 10:00 KST 스모크 테스트 결과 공유 확인",
      "동일 시점의 실패 트리아지 노트(action_items.md) 작성 여부 확인",
      "packageName 불일치 이슈의 실제 발생 원인(설정/컨트랙트) 점검",
      "Hara의 tarball 경로 확인 결과 확인",
      "최종 릴리스 승인 권한자 확정 여부 확인",
      "릴리스 노트에 내부 수요일 목표 포함 여부 최종 결정"
    ],
    "what_not_to_invent": [
      "고객명, 예산 수치, 보안 사건, 운영 장애, 법적 승인 요건, 미공개 오너, 미공개 마감기한",
      "원래 회의록에 없는 확정 책임자/일정/승인자 추정",
      "릴리스 노트 문구나 정책에 대한 임의 판단",
      "외부 자료 기반의 정답(그림의 정답/Golden/레퍼런스) 추론"
    ]
  },
  "non_invention_rules": [
    "이 출력은 PUBLIC_SAFE SYNTHETIC MEETING FIXTURE 정보만 사용한다.",
    "명시되지 않은 customer, budget, security, outage, legal, owner, deadline 사실을 추가하지 않는다.",
    "확정사항, 거부안, 내부 스트레치 목표, 위험, 미결 질문을 구분해 표기한다.",
    "시간/기한은 원문 표기에 있는 KST 기반 문장만 사용한다.",
    "추정이 필요한 항목은 source_certainty를 낮게 두거나 미지정으로 명시하고 단정하지 않는다."
  ]
}
